Add-Type -Assembly System.IO.Compression.FileSystem
$files = @(
    'C:\Users\Administrator\Desktop\dsc_gn7\can pe 자료\Microsoft_Word_Document.docx',
    'C:\Users\Administrator\Desktop\dsc_gn7\can pe 자료\Microsoft_Word_Document1.docx',
