Add-Type -Assembly System.IO.Compression.FileSystem
$base = 'C:\Users\Administrator\Desktop\dsc_gn7\can pe 자료'

function Read-Docx($path) {
    Write-Output "===== $([System.IO.Path]::GetFileName($path)) ====="
    try {
        $zip = [System.IO.Compression.ZipFile]::OpenRead($path)
        $entry = $zip.GetEntry('word/document.xml')
        if ($entry) {
            $sr = New-Object System.IO.StreamReader($entry.Open())
            $xml = [xml]$sr.ReadToEnd()
            $sr.Close()
            $ns = New-Object System.Xml.XmlNamespaceManager($xml.NameTable)
            $ns.AddNamespace('w','http://schemas.openxmlformats.org/wordprocessingml/2006/main')
            $paras = $xml.SelectNodes('//w:p', $ns)
            foreach ($p in $paras) {
                $texts = ($p.SelectNodes('.//w:t', $ns) | ForEach-Object { $_.InnerText }) -join ''
                if ($texts.Trim()) { Write-Output $texts }
            }
        }
        $zip.Dispose()
    } catch {
        Write-Output "Error: $($_.Exception.Message)"
    }
    Write-Output ''
}

$docxFiles = Get-ChildItem -Path $base -Filter '*.docx'
foreach ($f in $docxFiles) {
