Add-Type -Assembly System.IO.Compression.FileSystem

$base = Get-ChildItem 'C:\Users\Administrator\Desktop\dsc_gn7' -Directory | Where-Object { $_.Name -like 'can pe*' } | Select-Object -First 1

# Excel 파일 읽기 (xlsx = zip, xl/sharedStrings.xml + xl/worksheets/sheet*.xml)
$xlsxFiles = Get-ChildItem -Path $base.FullName -Filter '*.xlsx'
foreach ($f in $xlsxFiles) {
    Write-Output "`n===== $($f.Name) ====="
    try {
        $zip = [System.IO.Compression.ZipFile]::OpenRead($f.FullName)

        # 공유 문자열 테이블 읽기
        $ssEntry = $zip.GetEntry('xl/sharedStrings.xml')
        $strings = @()
        if ($ssEntry) {
            $sr = New-Object System.IO.StreamReader($ssEntry.Open())
            $ssXml = [xml]$sr.ReadToEnd()
            $sr.Close()
            $ns = New-Object System.Xml.XmlNamespaceManager($ssXml.NameTable)
            $ns.AddNamespace('x','http://schemas.openxmlformats.org/spreadsheetml/2006/main')
            foreach ($si in $ssXml.SelectNodes('//x:si', $ns)) {
                $texts = ($si.SelectNodes('.//x:t', $ns) | ForEach-Object { $_.InnerText }) -join ''
                $strings += $texts
            }
        }
        Write-Output "Shared strings: $($strings.Count)"

        # 시트 목록
        $sheets = $zip.Entries | Where-Object { $_.FullName -like 'xl/worksheets/sheet*.xml' } | Sort-Object Name
        Write-Output "Sheets: $($sheets.Count)"

        foreach ($sheet in $sheets) {
            Write-Output "`n--- $($sheet.Name) ---"
            $sr = New-Object System.IO.StreamReader($sheet.Open())
            $sheetXml = [xml]$sr.ReadToEnd()
            $sr.Close()
            $ns2 = New-Object System.Xml.XmlNamespaceManager($sheetXml.NameTable)
            $ns2.AddNamespace('x','http://schemas.openxmlformats.org/spreadsheetml/2006/main')
            $rows = $sheetXml.SelectNodes('//x:row', $ns2)
            $rowCount = 0
            foreach ($row in $rows) {
                $cells = $row.SelectNodes('x:c', $ns2)
                $vals = @()
                foreach ($c in $cells) {
                    $v = $c.SelectSingleNode('x:v', $ns2)
                    $vText = ''
                    if ($v) {
                        $vText = $v.InnerText
                        if ($c.GetAttribute('t') -eq 's' -and $strings.Count -gt 0) {
                            $idx = [int]$vText
                            if ($idx -lt $strings.Count) { $vText = $strings[$idx] }
                        }
                    }
                    $vals += $vText
                }
                $line = $vals -join ' | '
                if ($line.Trim()) {
                    Write-Output $line
                    $rowCount++
                    if ($rowCount -ge 100) { Write-Output "... (truncated at 100 rows)"; break }
                }
            }
        }
        $zip.Dispose()
    } catch {
        Write-Output "Error: $($_.Exception.Message)"
    }
}

