# Word 문서들을 텍스트로 추출
cat > /tmp/read_docx.ps1 << 'PSEOF'
param([string]$FilePath)
Add-Type -AssemblyName System.IO.Compression.FileSystem
try {
    $zip = [System.IO.Compression.ZipFile]::OpenRead($FilePath)
    $entry = $zip.GetEntry("word/document.xml")
    if ($entry) {
        $stream = $entry.Open()
        $reader = New-Object System.IO.StreamReader($stream)
        $xml = [xml]$reader.ReadToEnd()
        $reader.Close()
        $stream.Close()
        $ns = New-Object System.Xml.XmlNamespaceManager($xml.NameTable)
        $ns.AddNamespace("w", "http://schemas.openxmlformats.org/wordprocessingml/2006/main")
        $paragraphs = $xml.SelectNodes("//w:p", $ns)
        foreach ($p in $paragraphs) {
            $texts = $p.SelectNodes(".//w:t", $ns)
            $line = ""
            foreach ($t in $texts) { $line += $t.InnerText }
            if ($line.Trim() -ne "") { Write-Host $line }
        }
    }
    $zip.Dispose()
} catch {
    Write-Host "Error: $_"
}
PSEOF

powershell -ExecutionPolicy Bypass -File /tmp/read_docx.ps1 -FilePath "C:\Users\Administrator\Desktop\dsc_gn7\can pe 자료\Microsoft_Word_Document.docx" 2>/dev/null | head -100

# Excel 파일 내용 추출 - PowerShell COM 객체 사용
cat > /tmp/read_xlsx.ps1 << 'PSEOF'
param([string]$FilePath)
Add-Type -AssemblyName System.IO.Compression.FileSystem
try {
    $zip = [System.IO.Compression.ZipFile]::OpenRead($FilePath)

    # 시트 목록 확인
    $wbEntry = $zip.GetEntry("xl/workbook.xml")
    if ($wbEntry) {
        $stream = $wbEntry.Open()
        $reader = New-Object System.IO.StreamReader($stream)
        $wbXml = [xml]$reader.ReadToEnd()
        $reader.Close(); $stream.Close()
        $ns = New-Object System.Xml.XmlNamespaceManager($wbXml.NameTable)
        $ns.AddNamespace("x", "http://schemas.openxmlformats.org/spreadsheetml/2006/main")
        $sheets = $wbXml.SelectNodes("//x:sheet", $ns)
        Write-Host "=== Sheets ==="
        foreach ($s in $sheets) { Write-Host "  $($s.name)" }
    }

    # SharedStrings 로드
    $ssEntry = $zip.GetEntry("xl/sharedStrings.xml")
    $strings = @()
    if ($ssEntry) {
        $stream = $ssEntry.Open()
        $reader = New-Object System.IO.StreamReader($stream)
        $ssXml = [xml]$reader.ReadToEnd()
        $reader.Close(); $stream.Close()
        $ns2 = New-Object System.Xml.XmlNamespaceManager($ssXml.NameTable)
        $ns2.AddNamespace("x", "http://schemas.openxmlformats.org/spreadsheetml/2006/main")
        $siNodes = $ssXml.SelectNodes("//x:si", $ns2)
        foreach ($si in $siNodes) {
            $txt = ""
            $tNodes = $si.SelectNodes(".//x:t", $ns2)
            foreach ($t in $tNodes) { $txt += $t.InnerText }
            $strings += $txt
        }
    }

    # Sheet1 읽기
    $sheetEntry = $zip.GetEntry("xl/worksheets/sheet1.xml")
    if ($sheetEntry) {
        $stream = $sheetEntry.Open()
        $reader = New-Object System.IO.StreamReader($stream)
        $sheetXml = [xml]$reader.ReadToEnd()
        $reader.Close(); $stream.Close()
        $ns3 = New-Object System.Xml.XmlNamespaceManager($sheetXml.NameTable)
        $ns3.AddNamespace("x", "http://schemas.openxmlformats.org/spreadsheetml/2006/main")
        $rows = $sheetXml.SelectNodes("//x:row", $ns3)
        $rowCount = 0
        foreach ($row in $rows) {
            if ($rowCount++ -ge 30) { break }
            $cells = $row.SelectNodes("x:c", $ns3)
            $vals = @()
            foreach ($c in $cells) {
                $v = $c.SelectSingleNode("x:v", $ns3)
                if ($v) {
                    if ($c.GetAttribute("t") -eq "s") {
                        $idx = [int]$v.InnerText
                        if ($idx -lt $strings.Count) { $vals += $strings[$idx] }
                        else { $vals += $v.InnerText }
                    } else {
                        $vals += $v.InnerText
                    }
                } else { $vals += "" }
            }
            Write-Host ($vals -join "`t")
        }
    }
    $zip.Dispose()
} catch {
    Write-Host "Error: $_"
}
PSEOF

