powershell -ExecutionPolicy Bypass -File /tmp/read_xlsx.ps1 -FilePath "C:\Users\Administrator\Desktop\dsc_gn7\can pe 자료\Microsoft_Excel_Worksheet.xlsx" 2>/dev/null

